// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of [http.ServeMux].
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	http.Handler
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/api/collection", wrapper.DeleteCollection)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/collection", wrapper.PostCollection)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/api/context", wrapper.DeleteContext)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/context", wrapper.GetContext)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/context", wrapper.PostContext)
	m.HandleFunc(http.MethodDelete+" "+options.BaseURL+"/api/document", wrapper.DeleteDocument)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/document", wrapper.GetDocument)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/document", wrapper.PostDocument)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/embed", wrapper.PostEmbed)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/index", wrapper.PostIndex)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/list", wrapper.GetList)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/metadata", wrapper.GetMetadata)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/search", wrapper.GetSearch)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/status", wrapper.GetStatus)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/tag", wrapper.GetTag)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/tag", wrapper.PostTag)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/tags", wrapper.GetTags)

	return m
}

